/// `selection_knobs` f32 — each non-default knob's labels match its oracle.
#[test]
#[ignore = "un-ignore in 15-NN: needs the back-end fit + selection knobs"]
fn selection_knobs_f32() {
    let backend = capability::active_backend_name();
    capability::log_oracle_dtype(capability::FloatKind::F32, backend, "default");
    let case = load_npz(fixture("hdbscan_nested_f32_seed42.npz")).expect("load nested f32");
    run_selection_knobs(&case, "selection_knobs f32");
}

/// `selection_knobs` f64 — each non-default knob's labels (cpu; rocm skips).
#[test]
#[ignore = "un-ignore in 15-NN: needs the back-end fit + selection knobs"]
fn selection_knobs_f64() {
    if skip_f64("selection_knobs") {
        return;
    }
    let case = load_npz(fixture("hdbscan_nested_f64_seed42.npz")).expect("load nested f64");
    run_selection_knobs(&case, "selection_knobs f64");
}

fn run_selection_knobs(case: &OracleCase, label: &str) {
    // Each non-default-knob oracle label vector. 15-NN: fit `Hdbscan` with each
    // knob and replace the `got_*` clone with the fitted labels.
    for knob in [
        "labels_eom",
        "labels_leaf",
        "labels_maxcluster",
        "labels_alpha",
        "labels_epsilon",
    ] {
        let oracle = labels_i64(case, knob);
        let got = oracle.clone();
        let acc = best_match_accuracy_pinned_noise(&got, &oracle);
        assert!(
            (acc - 1.0).abs() < f64::EPSILON,
            "{label} [{knob}]: labels not a -1-pinned permutation of the oracle (acc={acc})"
        );
    }
}

// ---------------------------------------------------------------------------
// HDBS-01 / D-08: data-independent build validation — bad hyperparameters are
// rejected at `build()` with a typed `BuildError`, BEFORE any data is seen.
// (Extends the kept Phase-12 `build_rejects_bad_min_cluster_size`.) This gate
// RUNS now — the build path already exists on the shell.
// ---------------------------------------------------------------------------

/// BLDR-01: `Hdbscan::new()` equals `Hdbscan::builder().build()?` on the
/// hyperparameter subset (single-source defaults). Pure host comparison. KEPT
/// verbatim from the Phase-12 shell.
#[test]
fn defaults_equal() {
    let from_new = Hdbscan::<f64>::new();
    let from_builder = Hdbscan::<f64>::builder()
        .build::<f64>()
        .expect("default HdbscanBuilder builds");
    assert!(
        from_new.hyperparams_eq(&from_builder),
        "Hdbscan::new() and builder().build()? must agree on hyperparameters (BLDR-01)"
    );
}

/// D-08 build validation (HDBS-01): a `min_cluster_size < 2` is rejected at
/// `build()` with the typed `BuildError::InvalidMinClusterSize`, BEFORE any data.
/// (Extends the Phase-12 `build_rejects_bad_min_cluster_size`; 15-NN adds the
/// `min_samples`/`max_cluster_size`/`alpha`/minkowski-`p` cases as those typed
/// `BuildError` variants land.)
#[test]
fn build_validation() {
    let bad = Hdbscan::<f64>::builder()
        .min_cluster_size(1)
        .build::<f64>()
        .err();
    assert!(
        matches!(
            bad,
            Some(BuildError::InvalidMinClusterSize { min_cluster_size, .. })
                if min_cluster_size == 1
        ),
        "min_cluster_size < 2 must be BuildError::InvalidMinClusterSize, got {bad:?}"
    );

    // min_samples = Some(0) is rejected; Some(1) is accepted (15-03 / D-09).
    let bad_ms = Hdbscan::<f64>::builder()
        .min_samples(Some(0))
        .build::<f64>()
        .err();
    assert!(
        matches!(
            bad_ms,
            Some(BuildError::InvalidMinSamples { min_samples, .. }) if min_samples == 0
        ),
        "min_samples = Some(0) must be BuildError::InvalidMinSamples, got {bad_ms:?}"
    );
    assert!(
        Hdbscan::<f64>::builder()
            .min_samples(Some(1))
            .build::<f64>()
            .is_ok(),
        "min_samples = Some(1) must be accepted"
    );

    // max_cluster_size = 3 with min_cluster_size = 5 is rejected (neither 0 nor
    // >= mcs); 0 (unbounded) and 5 (== mcs) are accepted.
    let bad_mxc = Hdbscan::<f64>::builder()
        .min_cluster_size(5)
        .max_cluster_size(3)
        .build::<f64>()
        .err();
    assert!(
        matches!(
            bad_mxc,
            Some(BuildError::InvalidMaxClusterSize { max_cluster_size, min_cluster_size, .. })
                if max_cluster_size == 3 && min_cluster_size == 5
        ),
        "max_cluster_size below min_cluster_size must be InvalidMaxClusterSize, got {bad_mxc:?}"
    );
    assert!(
        Hdbscan::<f64>::builder()
            .min_cluster_size(5)
            .max_cluster_size(0)
            .build::<f64>()
            .is_ok(),
        "max_cluster_size = 0 (unbounded) must be accepted"
    );
    assert!(
        Hdbscan::<f64>::builder()
            .min_cluster_size(5)
            .max_cluster_size(5)
            .build::<f64>()
            .is_ok(),
        "max_cluster_size == min_cluster_size must be accepted"
    );

    // alpha <= 0 is rejected; alpha = 1.0 is accepted.
    let bad_alpha = Hdbscan::<f64>::builder().alpha(0.0).build::<f64>().err();
    assert!(
        matches!(
            bad_alpha,
            Some(BuildError::InvalidAlphaHdbscan { alpha, .. }) if alpha == 0.0
        ),
        "alpha = 0.0 must be BuildError::InvalidAlphaHdbscan, got {bad_alpha:?}"
    );
    assert!(
        Hdbscan::<f64>::builder().alpha(-1.0).build::<f64>().is_err(),
        "negative alpha must be rejected"
    );
    assert!(
        Hdbscan::<f64>::builder().alpha(1.0).build::<f64>().is_ok(),
        "alpha = 1.0 must be accepted"
    );

    // Metric::Minkowski { p < 1 } is rejected; p = 2.0 accepted; Precomputed
    // round-trips through the builder.
    let bad_p = Hdbscan::<f64>::builder()
        .metric(Metric::Minkowski { p: 0.5 })
        .build::<f64>()
        .err();
    assert!(
        matches!(
            bad_p,
            Some(BuildError::InvalidMinkowskiP { p, .. }) if p == 0.5
        ),
        "minkowski p < 1 must be BuildError::InvalidMinkowskiP, got {bad_p:?}"
    );
    assert!(
        Hdbscan::<f64>::builder()
            .metric(Metric::Minkowski { p: 2.0 })
            .build::<f64>()
            .is_ok(),
        "minkowski p = 2.0 must be accepted"
    );
    assert!(
        Hdbscan::<f64>::builder()
            .metric(Metric::Precomputed)
            .build::<f64>()
            .is_ok(),
        "Metric::Precomputed must construct"
    );
}

// ---------------------------------------------------------------------------
// HDBS-01 / T-15-OVF: the device front-end must not leak across re-fits, and must
// keep `peak_bytes` sub-quadratic (no full `n×n` resident — query-axis-tiled).
//
// WAVE-0: the shell `fit` is trivial; the re-fit-no-growth idiom (from the kept
// Phase-12 `fit_no_leak`) runs now over Euclidean default. The sub-quadratic
// `peak_bytes` assertion is added in 15-NN once the device front-end exists.
// ---------------------------------------------------------------------------

/// `memory_gate` — re-CONSTRUCT + re-fit at the same shape does not grow
/// `live_bytes` (the consuming `fit(self)` forces reconstruction each iteration).
/// The kept Phase-12 PoolStats idiom; 15-NN adds the sub-quadratic `peak_bytes`
/// gate once the n×n device front-end exists.
#[test]
fn memory_gate() {
    use mlrs_algos::typestate::Fit;
    use mlrs_backend::device_array::DeviceArray;
    use mlrs_backend::pool::BufferPool;
    use mlrs_backend::runtime::{self, ActiveRuntime};

    if skip_f64("memory_gate") {
        return;
    }

    let client = runtime::active_client();
    let mut pool: BufferPool<ActiveRuntime> = BufferPool::new(client);

    let n = 9usize;
    let p = 4usize;
    let x_host: Vec<f64> = (0..n * p).map(|i| i as f64).collect();
    let x_dev: DeviceArray<ActiveRuntime, f64> = DeviceArray::from_host(&mut pool, &x_host);

    let fitted = Hdbscan::<f64>::new()
        .fit(&mut pool, &x_dev, None, (n, p))
        .expect("first fit");
    drop(fitted);
    let live_after_first = pool.stats().live_bytes;

    const REFITS: usize = 4;
    for k in 0..REFITS {
        let fitted = Hdbscan::<f64>::new()
            .fit(&mut pool, &x_dev, None, (n, p))
            .expect("re-fit");
        drop(fitted);
        let live = pool.stats().live_bytes;
        assert!(
            live <= live_after_first,
            "live_bytes grew across re-construct+fit {k}: {live} > first {live_after_first}"
        );
    }
}

